codes.c:
#include <stdio.h>

int fib(int n) {
  if (n <= 1) return n;
  return fib(n - 1) + fib(n - 2);
}

int main() {
  int n = 6;
  printf("Fibonacci number at position %d: %d\n", n, fib(n));
  return 0;
}
// Output: Fibonacci number at position 6: 8

