codes.csharp:
using System;

class Program {
  static int Fib(int n) {
    if (n <= 1) return n;
    return Fib(n - 1) + Fib(n - 2);
  }

  static void Main() {
    int n = 6;
    Console.WriteLine($"Fibonacci number at position {n}: {Fib(n)}");
  }
}
// Output: Fibonacci number at position 6: 8

